🌌 {{ id }}
</p>
<button @click="$emit('close')" style="margin-top: 20px; padding: 8px 16px; cursor: pointer;">Close Overlay</button>
</div>
</div>
</template>
<script setup>
defineProps({ id: String })
defineEmits(['close'])
</script>

